    "directions": [
      {
        "id": "bourbon-challah-french-toast-casserole-directions",
        "title": "Directions",
        "steps": [
          {
            "id": "bourbon-challah-french-toast-casserole-step-1",
            "order": 1,
            "text": "Preheat the oven to 325°F (165°C). Generously coat a 9- × 13-inch (23 × 33cm) baking dish with cooking spray."
          },
          {
            "id": "bourbon-challah-french-toast-casserole-step-2",
            "order": 2,
            "text": "Place the challah slices on a baking sheet in a single layer, and bake for 15 to 20 minutes or until dried."
          },
          {
            "id": "bourbon-challah-french-toast-casserole-step-3",
            "order": 3,
            "text": "In a large bowl, whisk together the eggs, egg yolks, cinnamon, nutmeg, allspice, fine sea salt, and brown sugar until homogeneous. Whisk in the heavy whipping cream, milk, and bourbon."
          },
          {
            "id": "bourbon-challah-french-toast-casserole-step-4",
            "order": 4,
            "text": "Arrange the bread so it’s shingled in two rows in the baking dish and everything fits nice and snug. Pour the custard mixture on top, and refrigerate for a minimum of 45 minutes or overnight. (This is great to prep the night before you plan to have it for breakfast.)"
          },
          {
            "id": "bourbon-challah-french-toast-casserole-step-5",
            "order": 5,
            "text": "Preheat the oven to 350°F (180°C)."
          },
          {
            "id": "bourbon-challah-french-toast-casserole-step-6",
            "order": 6,
            "text": "Loosely tent the dish with foil to prevent the top of the casserole from burning. Place the dish in the oven, and bake for 30 to 35 minutes."
          },
          {
            "id": "bourbon-challah-french-toast-casserole-step-7",
            "order": 7,
            "text": "Remove the dish from the oven, and let cool at room temperature for 5 minutes. Top with maple syrup, whipped cream, and berries, then lightly dust with powdered sugar. Enjoy!"
          }
        ]
      }
    ],
